using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains the ML.NET ticket classification model at startup,
/// logs evaluation metrics, and saves the model to disk.
/// </summary>
public sealed class ModelTrainingService(
    ILogger<ModelTrainingService> logger,
    ModelMetadata modelMetadata) : IHostedService
{
    public const string ModelPath = "ticket_model.zip";

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Train/test split
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Build pipeline: featurize text + concatenate + train
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Train
        logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Extract label names from the Score column's slot metadata
        var predictions = model.Transform(split.TestSet);
        var scoreColumn = predictions.Schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        modelMetadata.Labels = slotNames.DenseValues()
            .Select(v => v.ToString()).ToArray();
        logger.LogInformation("Label order: {Labels}", string.Join(", ", modelMetadata.Labels));

        // Evaluate
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        logger.LogInformation("===== Model Evaluation Metrics =====");
        logger.LogInformation("  Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("  Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("  Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("  Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);

        for (var i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            var label = i < modelMetadata.Labels.Length ? modelMetadata.Labels[i] : $"Class {i}";
            logger.LogInformation("  Per-class log loss ({Label}): {LogLoss:F4}",
                label, metrics.PerClassLogLoss[i]);
        }

        // Save model
        var modelSavePath = Path.Combine(AppContext.BaseDirectory, ModelPath);
        mlContext.Model.Save(model, data.Schema, modelSavePath);
        logger.LogInformation("Model saved to {Path}", modelSavePath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

